    <div v-else class="text-center py-5 rounded"
         style="background:#f9fafb;border:2px dashed #e5e7eb;">
      <p class="mb-3" style="color:#6b7280;font-size:0.9375rem;">No recommendations available yet. Log more meals to get personalized suggestions!</p>
    </div>

  </div>
</template>

<script setup>
import { ref, computed, onMounted, watch } from 'vue'
import { useRoute, useRouter } from 'vue-router'
import { apiFetch } from '../auth.js'
import { favourites, loadingFavs, loadFavourites } from '../recipesStore.js'

const route = useRoute()
const router = useRouter()

const viewDate = ref(new Date())
const dateAnnouncement = ref('')

const formattedDate = computed(() =>
  viewDate.value.toLocaleDateString('en-GB', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' })
)

// Use local date instead of UTC to avoid timezone offset issues
const referenceDate = computed(() => {
  const d = viewDate.value
  const year = d.getFullYear()
  const month = String(d.getMonth() + 1).padStart(2, '0')
  const day = String(d.getDate()).padStart(2, '0')
  return `${year}-${month}-${day}`
})

const isToday = computed(() => {
  const today = new Date()
  const todayStr = `${today.getFullYear()}-${String(today.getMonth() + 1).padStart(2, '0')}-${String(today.getDate()).padStart(2, '0')}`
  return referenceDate.value === todayStr
})

function handlePrevDay() {
  const d = new Date(viewDate.value)
  d.setDate(d.getDate() - 1)
  viewDate.value = d
  dateAnnouncement.value = `Navigated to ${formattedDate.value}`
}

function handleNextDay() {
  const d = new Date(viewDate.value)
  d.setDate(d.getDate() + 1)
  viewDate.value = d
  dateAnnouncement.value = `Navigated to ${formattedDate.value}`
}

const dashboard = ref(null)
const loading = ref(true)
const error = ref('')
const recommendedRecipesDisplayCount = ref(3)

const professional = ref(null)
const loadingPro = ref(true)
const recentMessages = ref([])

const goals = ref([])
const loadingGoals = ref(true)

const pendingInvites = ref([])

// Computed calorie budget from goals (calories nutrient)
const calorieBudget = computed(() => {
  const calorieGoal = goals.value.find(g => g.nutrient?.code === 'calories')
  return calorieGoal?.targetMax ?? calorieGoal?.targetMin ?? 2000 // fallback to 2000 if no goal set
})

onMounted(async () => {
  // Check if there's a date in the URL query parameter
  if (route.query.date) {
    const dateFromQuery = new Date(route.query.date)
    if (!isNaN(dateFromQuery.getTime())) {
      viewDate.value = dateFromQuery
    }
  }
  await Promise.all([loadDashboard(), loadProfessional(), loadGoals(), loadFavourites(), loadInvitations()])
})

watch(viewDate, () => {
  loadDashboard()
  // Update URL when date changes
  router.replace({ query: { date: referenceDate.value } })
})

// single request returns diary entries, nutrition preview and weekly trend all at once
async function loadDashboard() {
  loading.value = true
  error.value = ''
  try {
    const params = new URLSearchParams({ date: referenceDate.value })
    const res = await apiFetch(`/api/diary/dashboard?${params}`)
    const data = await res.json().catch(() => ({}))
    if (!res.ok) {
      error.value = data.message || data.error || 'Failed to load dashboard'
      return
    }
    dashboard.value = data.dashboardData ?? data
  } catch (err) {
    error.value = 'Network error - could not load dashboard'
    console.error('Dashboard load error:', err)
  } finally {
    loading.value = false
  }
}

async function loadProfessional() {
  loadingPro.value = true
  try {
    const res = await apiFetch('/api/client/professionals')
    const data = await res.json().catch(() => ({}))
    if (res.ok) {
      professional.value = (data.professionals ?? [])[0] ?? null
      if (professional.value) await loadLatestMessage()
    }
  } catch {
    // non-critical, silently ignore
  } finally {
    loadingPro.value = false
  }
}

async function loadLatestMessage() {
  try {
    const res = await apiFetch(`/api/client/professionals/${professional.value.professionalId}/messages`)
    const data = await res.json().catch(() => ({}))
    if (res.ok) recentMessages.value = (data.messages ?? []).slice(0, 2).reverse()
  } catch {
    // non-critical, silently ignore
  }
}

async function loadGoals() {
  loadingGoals.value = true
  try {
    const res = await apiFetch('/api/goals')
    const data = await res.json().catch(() => ({}))
    if (res.ok) goals.value = data.goals ?? []
  } catch {
    // non-critical, silently ignore
  } finally {
    loadingGoals.value = false
  }
}

async function loadInvitations() {
  try {
    const res = await apiFetch('/api/client/client-invitations')
    const data = await res.json().catch(() => ({}))
    if (res.ok) pendingInvites.value = (data.invitations ?? []).map(i => ({ ...i, _busy: false, _action: '' }))
  } catch {
    // non-critical, silently ignore
  }
}

async function respondToInvite(inv, action) {
  inv._busy = true
  inv._action = action
  try {
    const res = await apiFetch(`/api/client/client-invitations/${inv.professionalId}/${action}`, { method: 'POST' })
    if (res.ok) {
      await Promise.all([loadProfessional(), loadInvitations()])
    }
  } catch {
    // non-critical
  } finally {
    inv._busy = false
    inv._action = ''
  }
}

const quickStats = computed(() => dashboard.value?.quickStats ?? {})
const foodDiaryPreview = computed(() => (dashboard.value?.foodDiaryPreview ?? []).filter(e => (e.items?.length ?? 0) > 0))
const nutritionPreview = computed(() => dashboard.value?.nutritionPreview ?? [])
const recommendedRecipes = computed(() => dashboard.value?.recommendedRecipes ?? [])
const displayedRecommendedRecipes = computed(() => recommendedRecipes.value.slice(0, recommendedRecipesDisplayCount.value))
const hasMoreRecommendations = computed(() => recommendedRecipes.value.length > recommendedRecipesDisplayCount.value)
const caloriesToday = computed(() => quickStats.value.calories_today ?? 0)
const caloriePercent = computed(() => Math.round((caloriesToday.value / calorieBudget.value) * 100))
const caloriesRemaining = computed(() => calorieBudget.value - Math.round(caloriesToday.value))

function loadMoreRecommendations() {
  const remaining = recommendedRecipes.value.length - recommendedRecipesDisplayCount.value
  recommendedRecipesDisplayCount.value += Math.min(remaining, 9)
}

// Computed macro references from goals
const MACRO_REFS = computed(() => {
  const macros = ['protein', 'carbohydrates', 'fat', 'fibre']
  const labels = { protein: 'Protein', carbohydrates: 'Carbs', fat: 'Fat', fibre: 'Fibre' }
  const result = {}
  
  macros.forEach(code => {
    const goal = goals.value.find(g => g.nutrient?.code === code)
    const targetValue = goal?.targetMax ?? goal?.targetMin
    result[code] = {
      label: labels[code],
      ref: targetValue ?? (code === 'protein' ? 50 : code === 'carbohydrates' ? 260 : code === 'fibre' ? 30 : 70), // fallback values
      unit: 'g'
    }
  })
  
  return result
})

const nutrientLabels = { protein: 'Protein', carbohydrates: 'Carbs', fat: 'Fat', fibre: 'Fibre' }

const macroSummary = computed(() =>
  Object.entries(MACRO_REFS.value).map(([code, meta]) => {
    const n = nutritionPreview.value.find(x => x.code === code)
    const amount = Math.round(Number(n?.totalAmount ?? 0))
    return {
      code,
      label: meta.label,
      unit: meta.unit,
      amount,
      pct: Math.min(Math.round((amount / meta.ref) * 100), 100),
    }
  })
)

const WEEK_DAYS = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat']
const MAX_BAR_H = 90

// bar heights are relative to the tallest day so the chart never overflows its container
const weekBars = computed(() => {
  const trend = dashboard.value?.weeklyCaloryTrend ?? []
  if (!trend.length) {
    return Array.from({ length: 7 }, () => ({ day: '-', date: '', val: '-', height: 0, over: false, isToday: false }))
  }
  const maxCal = Math.max(...trend.map(d => d.calories), calorieBudget.value)
  return trend.map((d) => {
    const cal = Math.round(d.calories)
    const isToday = d.date === referenceDate.value
    const dateObj = new Date(d.date + 'T00:00:00')
    const dayName = WEEK_DAYS[dateObj.getDay()]
    return {
      day: isToday ? 'Today' : dayName,
      date: d.date,
      val: cal > 0 ? String(cal) : '-',
      height: cal > 0 ? Math.max(3, Math.round((cal / maxCal) * MAX_BAR_H)) : 0,
      over: cal > calorieBudget.value,
      isToday,
    }
  })
})

function nutrientPercent(n) {
  const meta = MACRO_REFS.value[n.code]
  if (!meta) return 0
  return Math.min(Math.round((Number(n.totalAmount) / meta.ref) * 100), 100)
}

function formatAmount(n) {
  const value = Number(n.totalAmount ?? 0)
  const unit = n.unit ?? 'g'
  return `${Math.round(value)}${unit}`
}

function initialsFor(name) {
  if (!name) return '?'
  return name.trim().split(/\s+/).slice(0, 2).map(p => p[0].toUpperCase()).join('') || '?'
}

function goalRange(goal) {
  const min = goal.targetMin
  const max = goal.targetMax
  const unit = goal.nutrient?.unit ? ` ${goal.nutrient.unit}` : ''
  if (min != null && max != null) return `${min}–${max}${unit}`
  if (min != null) return `≥ ${min}${unit}`
  if (max != null) return `≤ ${max}${unit}`
  return ''
}
</script>

<style scoped>
/* RouterLink (<a>) is inline by default — force block so the outline
   draws as a full rectangle around the card, not an inline snippet. */
.overview-card-link {
  display: block;
}

/* Match the card's 12px radius and give a bit more offset so the ring
   sits clearly outside the card's existing dark-green border. */
.overview-card-link:focus-visible {
  outline: 3px solid var(--gf-green);
  outline-offset: 4px;
  border-radius: 12px;
}
</style>